import{_ as l,p as i,q as e,a1 as a}from"./framework-7d8e42ec.js";const r={},u=a('<h1 id="实践出真理" tabindex="-1"><a class="header-anchor" href="#实践出真理" aria-hidden="true">#</a> 实践出真理</h1><p>在探寻合适的微前端方案的路上，我将上一章所提到的方案，全部实践了一遍，具体的 demo 案例代码，已经给到各项目组前端同事</p><p>优劣总结如下：</p><h2 id="模块联邦-module-federation" tabindex="-1"><a class="header-anchor" href="#模块联邦-module-federation" aria-hidden="true">#</a> 模块联邦 Module Federation</h2><ul><li><p>优点</p><ul><li>去中心化</li><li>真正的微服务</li></ul></li><li><p>缺点</p><ul><li>无法动态引入远程的模块</li><li>产生了循环引用的问题</li><li>remote 方，开发模式下独立开发时热更新失效</li><li>开发模式无法与生产模式交互</li></ul></li></ul><h2 id="乾坤-模块联邦" tabindex="-1"><a class="header-anchor" href="#乾坤-模块联邦" aria-hidden="true">#</a> 乾坤 + 模块联邦</h2><ul><li><p>优点</p><ul><li>htmlEntry（不用关心 js 的 hash，可动态加载 js）</li><li>集成迁移简单（以 html 为入口，完全不用关心子应用技术实现）</li><li>沙箱隔离</li><li>结合模块联邦，亦可做到模块互联</li></ul></li><li><p>缺点</p><ul><li>模块互联需要结合模块联邦</li><li>拥有模块联邦的所有缺点</li></ul></li></ul><h2 id="single-spa" tabindex="-1"><a class="header-anchor" href="#single-spa" aria-hidden="true">#</a> Single-spa</h2><ul><li><p>优点</p><ul><li>第三方依赖共享</li></ul></li><li><p>缺点：</p><ul><li>第三方依赖共享</li><li>以 js 为入口，只能加载固定的 js（需要关注子应用的实现，确定加载的js文件）</li><li>无沙箱隔离</li><li>各种引用</li></ul></li></ul><p>其他： 因为多个vue实例在同一个document里，需要避免全局变量污染、全局监听污染、样式污染等，需要制定接入规范。<br></p><p>使用了external抽离公共模块(比如Vue、Vue-router等)后，构造函数(或者Class)的污染也需要避免，比如Vue.mixin、Vue.components、Vue .use等等都需要做一些额外的工作去避免它们产生冲突。<br></p><p>如果你也想要tab切换不刷新(使用keep-alive)，那需要做的工作更多，主要是处理缓存，防止堆内存溢出（用chrome自带的performance monitor查看），还有项目间切换时路由钩子等等的处理</p><h2 id="microapp" tabindex="-1"><a class="header-anchor" href="#microapp" aria-hidden="true">#</a> MicroApp</h2><ul><li><p>优点：</p><ul><li>集成简单</li><li>js沙箱、样式隔离、元素隔离、预加载、数据通信、静态资源补全</li><li>体积小</li><li>应用嵌套（多个子应用共存，业务组件复用）</li></ul></li><li><p>缺点：</p><ul><li>社区目前不完善</li><li>使用者需要对框架的路由（vue-router....）熟练</li></ul></li></ul>',14),t=[u];function p(n,d){return i(),e("div",null,t)}const o=l(r,[["render",p],["__file","practice.html.vue"]]);export{o as default};
